module RefModule(
    clk,
	 clr,
	 def,
	 phase,
	 clk2,
    adr
);input clk;
input clr;
input [31:0]def;
input [7:0]phase;
output clk2;
output [7:0]adr;

reg [31:0]cnt = 0;

  wire _n01 = cnt[31:24][0] ^ phase[7:0][0];
  wire _c01 = cnt[31:24][0] & phase[7:0][0];
  wire _n02 = cnt[31:24][1] ^ phase[7:0][1] ^ _c01;
  wire _c02 = (cnt[31:24][1] & phase[7:0][1]) | (cnt[31:24][1] & _c01) | (phase[7:0][1] & _c01);
  wire _n03 = cnt[31:24][2] ^ phase[7:0][2] ^ _c02;
  wire _c03 = (cnt[31:24][2] & phase[7:0][2]) | (cnt[31:24][2] & _c02) | (phase[7:0][2] & _c02);
  wire _n04 = cnt[31:24][3] ^ phase[7:0][3] ^ _c03;
  wire _c04 = (cnt[31:24][3] & phase[7:0][3]) | (cnt[31:24][3] & _c03) | (phase[7:0][3] & _c03);
  assign adr = {_n01, _n02, _n03, _n04};

assign clk2 = cnt[31];

always @(posedge clk or posedge clr) begin
    if (clr)
        cnt <= 0;
    else
        cnt <= cnt + def;
end

endmodule
